INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (1, '2024-01-05', 10, 5, 3, 1, 10, 'Hoy fue la primera sesión con el paciente utilizando realidad virtual para tratar su fobia a las alturas. Iniciamos con una introducción al equipo de VR y realizamos una evaluación inicial de su nivel de ansiedad. El paciente fue expuesto a una simulación básica de estar en un edificio de baja altura, observando el paisaje desde una ventana.', 'Al principio me sentí nerviosa usando el equipo de VR, pero una vez que me acostumbré, la experiencia fue interesante. Sin embargo, mirar hacia afuera desde una ventana, aunque no era muy alto, me produjo bastante ansiedad.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (2, '2024-01-12', 75, 30, 3, 1, 20, 'El paciente mostró signos significativos de ansiedad al estar en un balcón virtual. Se realizaron ejercicios de respiración para reducir la ansiedad.', 'Me sentí bastante nervioso al principio, pero después de los ejercicios de respiración, me calmé un poco.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (3, '2024-01-19', 60, 20, 3, 1, 30, 'El paciente tuvo una respuesta moderada de ansiedad al observar la vista desde una ventana en un edificio alto. Logró mantenerse en la escena durante 5 minutos.', 'Al principio fue aterrador, pero después de unos minutos me acostumbré un poco.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (4, '2024-01-26', 80, 40, 3, 1, 40, 'El paciente presentó un alto nivel de activación al caminar por un puente virtual. Se utilizó la técnica de desensibilización sistemática.', 'Sentí mucha tensión y mi corazón latía rápido. Fue difícil mantener la calma.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (5, '2024-02-02', 50, 10, 3, 1, 50, 'El paciente tuvo una activación leve al subir en un ascensor virtual. La experiencia fue corta para evitar una respuesta de ansiedad intensa.', 'No estuvo tan mal como pensé, pero aún así me sentí un poco incómodo.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (6, '2024-02-09', 90, 50, 3, 1, 60, 'El paciente mostró una alta ansiedad al estar en una plataforma al aire libre en un rascacielos virtual. Se implementaron técnicas de grounding para ayudar a reducir la ansiedad.', 'Fue muy intenso, me sudaban las manos y me costaba respirar. Las técnicas de grounding me ayudaron un poco.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (7, '2024-02-16', 65, 25, 3, 1, 70, 'El paciente se expuso a una terraza en un edificio medio. Hubo ansiedad moderada, pero pudo mantenerse en la escena durante 10 minutos.', 'Estaba nervioso pero lo pude soportar mejor de lo que esperaba.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (8, '2024-02-23', 55, 15, 3, 1, 80, 'El paciente experimentó ansiedad moderada al estar en un balcón cerrado. Utilizó técnicas de visualización para calmarse.', 'Al principio sentí miedo, pero las visualizaciones me ayudaron a relajarme un poco.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (9, '2024-03-01', 70, 35, 3, 1, 90, 'El paciente enfrentó ansiedad alta al cruzar un puente colgante virtual. Se hicieron pausas frecuentes para evitar sobrecarga.', 'Fue muy aterrador, pero las pausas me ayudaron a manejar la situación.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (10, '2024-03-08', 85, 45, 3, 1, 100, 'El paciente mostró una alta respuesta de ansiedad en una montaña rusa virtual. Se utilizaron técnicas de respiración profunda para controlar la ansiedad.', 'Sentí mucha ansiedad y miedo, pero respirar profundamente me ayudó a calmarme un poco.');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (11, '2024-07-14', 37, 97, 3, 1, 88, 'Pruebas terapeutaPruebas terapeutaPruebas terapeutaPruebas terapeutaPruebas terapeuta', 'Paciente: pruebas pacientepruebas pacientepruebas pacientepruebas pacientepruebas paciente');
INSERT INTO session (id, session_date, activation_level, exposure_level, user_id, mental_disorder_id, progress, therapist_notes, user_notes) VALUES (12, '2024-07-14', 35, 8, 2, 3, 5, 'Primera sesion', 'No quiero volver');
